javascript:(async function(){

const APP="DMR-PDF-DOWNLOADED";
const VERSION="2026.05.04-PRO";
const API_PRINT="https://mevzuat.sinerjias.com.tr/api/mev/print/get-url";
const JSZIP_URL="https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js";
const STORAGE_KEY="DMR_ARCHIVER_STATE_PRO";

const PRO={
  CONCURRENCY:1,
  REQUEST_DELAY_MS:250,
  MAX_FILE_NAME:220,
  MAX_FOLDER_NAME:220,
  AUTO_RETRY:1
};

const CONFIG={
  yuksek:{
    label:"Yüksek Mahkeme",
    list:"https://mevzuat.sinerjias.com.tr/api/mev/daily/yuksekmahkeme-get-gunluk",
    tipId:2,
    type:"YuksekMahkemePayloadES",
    prefix:"yuksek-mahkeme"
  },
  istinaf:{
    label:"İstinaf",
    list:"https://mevzuat.sinerjias.com.tr/api/mev/daily/istinaf-get-gunluk",
    tipId:4,
    type:"IstinafPayloadES",
    prefix:"istinaf"
  }
};

let CANCEL=false;
let UI={total:0,current:0,added:0,failed:0,skipped:0,last:"",startedAt:0};

function debug(){console.log.apply(console,["["+APP+"]"].concat([].slice.call(arguments)));}
function sleep(ms){return new Promise(r=>setTimeout(r,ms));}
function pad(n){return String(n).padStart(2,"0");}
function today(){let d=new Date();return d.getFullYear()+"-"+pad(d.getMonth()+1)+"-"+pad(d.getDate());}
function parseDate(s){let p=String(s||"").split("-").map(Number);return new Date(p[0],p[1]-1,p[2]);}
function fmtDate(d){return d.getFullYear()+"-"+pad(d.getMonth()+1)+"-"+pad(d.getDate());}
function range(s,e){let a=[],d=parseDate(s),x=parseDate(e);while(d<=x){a.push(fmtDate(d));d.setDate(d.getDate()+1);}return a;}
function validDate(s){if(!/^\d{4}-\d{2}-\d{2}$/.test(String(s||"")))return false;let p=s.split("-").map(Number),d=new Date(p[0],p[1]-1,p[2]);return d.getFullYear()===p[0]&&d.getMonth()===p[1]-1&&d.getDate()===p[2];}
function ext(f){return f==="WORD"?"docx":f==="UDF"?"udf":"pdf";}
function norm(s){return String(s||"").toLocaleUpperCase("tr-TR").replace(/\s+/g," ").trim();}
function safe(s,max=220){return String(s||"KONUSUZ").replace(/[\\/:*?"<>|]/g,"-").replace(/[\u0000-\u001F\u007F]/g,"").replace(/\s+/g," ").trim().slice(0,max)||"KONUSUZ";}
function stripHtml(s){let d=document.createElement("div");d.innerHTML=String(s||"");return d.innerText||d.textContent||"";}
function quotaText(t){t=String(t||"").toLocaleLowerCase("tr-TR");return t.includes("günlük işlem kotasına ulaştınız")||t.includes("günlük işlem kotasi")||t.includes("günlük işlem kotası")||t.includes("islem kotasina ulas")||t.includes("işlem kotasına ulaş")||t.includes("too many requests")||t.includes("quota");}
function runKey(p,f){return [p.kind,p.start,p.end,p.format,f].join("|");}
function saveState(o){try{localStorage.setItem(STORAGE_KEY,JSON.stringify({...o,savedAt:new Date().toISOString(),version:VERSION}));}catch(e){}}
function loadState(){try{return JSON.parse(localStorage.getItem(STORAGE_KEY)||"null");}catch(e){return null;}}
function clearState(){try{localStorage.removeItem(STORAGE_KEY);}catch(e){}}

async function postJson(url,body){
  let r=await fetch(url,{method:"POST",credentials:"include",headers:{"Content-Type":"application/json","Accept":"application/json, text/plain, */*"},body:JSON.stringify(body)});
  let t=await r.text();
  if(r.status===429||quotaText(t))throw new Error("LIMIT");
  if(!r.ok){debug("HTTP_ERROR",url,r.status,t);throw new Error("HTTP_"+r.status);}
  try{return JSON.parse(t);}catch(e){return t;}
}
function arr(r){if(Array.isArray(r))return r;if(r&&Array.isArray(r.data))return r.data;if(r&&Array.isArray(r.content))return r.content;if(r&&Array.isArray(r.result))return r.result;if(r&&r.data&&Array.isArray(r.data.content))return r.data.content;if(r&&r.result&&Array.isArray(r.result.content))return r.result.content;return [];}

async function fetchLists(cfg,dates){
  let all=[];
  for(let d of dates){
    let page=0;
    while(true){
      log("Liste hazırlanıyor\nTür: "+cfg.label+"\nTarih: "+d+"\nSayfa: "+(page+1));
      let resp=await postJson(cfg.list,{tarih:d,page:page,size:100,loc:"open"});
      let list=arr(resp);
      if(!list.length)break;
      all.push({date:d,page:page,list:list});
      if(list.length<100)break;
      page++;
      await sleep(120);
    }
  }
  return all;
}

function getRows(){
  let xpath="/html/body/div[1]/div[1]/div[1]/div/div[2]/div[4]/div[2]/div[2]/div/div/div/div/div/div/div[2]/table/tbody";
  let tbody=document.evaluate(xpath,document,null,XPathResult.FIRST_ORDERED_NODE_TYPE,null).singleNodeValue;
  let rows=tbody?[...tbody.querySelectorAll("tr")]:[...document.querySelectorAll("table tbody tr, table tr")];
  return rows.filter(x=>norm(x.innerText).length>10);
}
function lettersFromText(text){let t=norm(text),out=[];let ms=[...t.matchAll(/\b\d+\s*\/\s*([A-ZÇĞİÖŞÜ]{1,12})\b/g)];for(let m of ms){if(m[1])out.push(m[1].trim());}return [...new Set(out)];}
function daireNoFromText(text){let m=String(text||"").match(/\b(\d+)\s*\/\s*[A-ZÇĞİÖŞÜ]{1,12}\b/i);return m?String(m[1]).trim():"";}
function apiDaireRaw(it){return String(it?.daireadi||it?.daireAdi||it?.daire||it?.daireAd||it?.daireBilgisi||it?.birimAdi||it?.birim||"").trim();}
function apiDaireNo(it){let m=apiDaireRaw(it).match(/\d+/);return m?m[0]:"";}
function apiKonu(it){return stripHtml(it?.konu||it?.konuAdi||it?.konuadi||it?.subject||it?.baslik||"").trim();}
function apiCourt(it){return String(it?.ymadi||it?.mahkemeAdi||it?.courtName||it?.mahkeme||"Mahkeme").trim();}

function guessKonu(cells){
  let c=cells.map(x=>x.trim()).filter(x=>x.length>=8).filter(x=>!/^\d+\s*\/\s*[A-ZÇĞİÖŞÜ]+$/.test(x)).filter(x=>!/\b\d{4}\s*\/\s*\d+\b/.test(x)).filter(x=>!/\b\d{2}\.\d{2}\.\d{4}\b/.test(x));
  c.sort((a,b)=>b.length-a.length);
  return c[0]||"";
}

function domIndex(){
  let byNo=new Map(),flat=[];
  for(let tr of getRows()){
    let cells=[...tr.children].map(td=>norm(td.innerText));
    let raw=tr.innerText||"";
    let text=norm(raw);
    let no=daireNoFromText(text);
    let letters=lettersFromText(text);
    let row={raw,text,cells,daireNo:no,letters,konuGuess:guessKonu(cells)};
    flat.push(row);
    if(no){if(!byNo.has(no))byNo.set(no,[]);byNo.get(no).push(row);}
  }
  debug("DOM_INDEX",{rows:flat.length,nos:[...byNo.keys()]});
  return {flat,byNo};
}

function enrichItem(it,idx){
  let no=apiDaireNo(it);
  let konu=apiKonu(it);
  let best=null;
  if(no&&idx.byNo.has(no)){
    let cand=idx.byNo.get(no);
    if(konu)best=cand.find(r=>r.text.includes(norm(konu).slice(0,40)));
    if(!best){
      let eY=String(it?.esasYil||""),eN=String(it?.esasNo||""),kY=String(it?.kararYil||""),kN=String(it?.kararNo||"");
      best=cand.find(r=>{let t=r.text;let eh=eY&&eN&&t.includes(eY)&&t.includes(eN);let kh=kY&&kN&&t.includes(kY)&&t.includes(kN);return eh||kh;});
    }
    if(!best)best=cand[0];
  }
  let letters=best&&best.letters&&best.letters.length?best.letters:lettersFromText(apiDaireRaw(it));
  let daireText=no&&letters.length?no+" / "+letters.join(","):apiDaireRaw(it);
  return {...it,__daireLetters:[...new Set(letters)],__daireText:daireText,__konu:konu||(best&&best.konuGuess)||"KONUSUZ",__domRowText:(best&&best.text)||""};
}
function enrichAll(all){let idx=domIndex();return all.map(b=>({...b,list:b.list.map(it=>enrichItem(it,idx))}));}
function buildOptions(all){let s=new Set();for(let b of all){for(let it of b.list){for(let l of it.__daireLetters||[]){if(l)s.add(norm(l));}}}let vals=[...s].sort((a,b)=>a.localeCompare(b,"tr"));return [{value:"ALL",label:"Tümü"}].concat(vals.map(x=>({value:x,label:x})));}
function passFilter(it,f){if(!f||f==="ALL")return true;return (it.__daireLetters||[]).some(x=>norm(x)===norm(f));}

function looksId(s){return typeof s==="string"&&s.length>20&&/^[A-Za-z0-9+/=_-]+$/.test(s);}
function tryAtob(s){try{return atob(s);}catch(e){return"";}}
function ids(it){
  let fields=[it?.id,it?.payloadId,it?.printId,it?.kararId,it?.documentId].filter(Boolean).map(String);
  let out=[];
  for(let raw of fields){if(looksId(raw))out.push(raw);let once=tryAtob(raw);if(looksId(once))out.push(once);let twice=once?tryAtob(once):"";if(looksId(twice))out.push(twice);}
  return [...new Set(out)];
}
async function headText(blob,len=8){let buf=await blob.slice(0,len).arrayBuffer();let bytes=new Uint8Array(buf);return [...bytes].map(b=>String.fromCharCode(b)).join("");}
async function validBlob(blob,format){
  if(!blob||blob.size<1000)return false;
  let type=String(blob.type||"").toLowerCase();let h=await headText(blob,8);
  if(format==="PDF")return h.startsWith("%PDF")||type.includes("pdf");
  if(format==="WORD")return h.startsWith("PK")||type.includes("word")||type.includes("officedocument");
  if(format==="UDF"){let bad=h.startsWith("<!DO")||h.startsWith("<html")||h.startsWith("{");return !bad&&blob.size>1000;}
  return blob.size>1000;
}
function findUrlDeep(o){if(!o)return"";if(typeof o==="string")return /^https?:\/\//i.test(o)?o:"";if(Array.isArray(o)){for(let x of o){let u=findUrlDeep(x);if(u)return u;}}if(typeof o==="object"){for(let k in o){let u=findUrlDeep(o[k]);if(u)return u;}}return"";}

async function tryPrint(cfg,it,format,id){
  let payload={tipId:cfg.tipId,type:cfg.type,payload:{id:id},yazdirEnum:format};
  debug("PRINT_REQUEST",payload);
  let data=await postJson(API_PRINT,payload);
  let url=findUrlDeep(data);
  if(!url){debug("URL_NOT_FOUND",id,data);return null;}
  let r=await fetch(url,{method:"GET",credentials:"include"});
  if(r.status===429)throw new Error("LIMIT");
  if(!r.ok){let txt="";try{txt=await r.text();}catch(e){}if(quotaText(txt))throw new Error("LIMIT");debug("FILE_HTTP_ERROR",r.status,url,txt);return null;}
  let blob=await r.blob();
  if(!(await validBlob(blob,format))){debug("INVALID_BLOB",{id,format,type:blob.type,size:blob.size});return null;}
  return blob;
}
async function getFile(cfg,it,format){let candidates=ids(it);debug("ID_CANDIDATES",{listId:it?.id,candidates});for(let id of candidates){let b=await tryPrint(cfg,it,format,id);if(b)return b;}return null;}

function konuIlkBolum(konu){
  konu=String(konu||"").trim();
  if(konu.indexOf("-")>-1){
    konu=konu.split("-")[0].trim();
  }
  if(!konu)return "KONUSUZ";
  konu=konu.toLocaleLowerCase("tr-TR");
  konu=konu.split(" ").filter(Boolean).map(function(w){
    return w.charAt(0).toLocaleUpperCase("tr-TR")+w.slice(1);
  }).join(" ");
  return konu;
}

function folderName(it){
  let konu=it.__konu||apiKonu(it)||"KONUSUZ";
  return safe(konuIlkBolum(konu),PRO.MAX_FOLDER_NAME);
}
function siteFileName(it){
  let title=it?.dosyaAdi||it?.dosyaadi||it?.fileName||it?.filename||it?.adi||it?.baslik||it?.kararAdi||it?.documentName||it?.name||"";
  title=stripHtml(title).trim();
  if(title)return safe(title,PRO.MAX_FILE_NAME);
  let parts=[apiCourt(it),it.__daireText||apiDaireRaw(it),it.esasYil&&it.esasNo?"E-"+it.esasYil+"-"+it.esasNo:"",it.kararYil&&it.kararNo?"K-"+it.kararYil+"-"+it.kararNo:"",it.kararTarihi?"Tarih-"+it.kararTarihi:""];
  return safe(parts.filter(Boolean).join(" - "),PRO.MAX_FILE_NAME);
}
function uniqueName(used,folder,base,extension){base=safe(base,PRO.MAX_FILE_NAME);let name=base+"."+extension;let key=folder+"/"+name;let n=2;while(used.has(key)){name=base+" ("+n+")."+extension;key=folder+"/"+name;n++;}used.add(key);return name;}
function csvEsc(v){let s=String(v??"");if(/[;"\n\r]/.test(s))return `"${s.replace(/"/g,'""')}"`;return s;}
function makeCsv(headers,rows){let body=[headers.map(csvEsc).join(";"),...rows.map(r=>headers.map(h=>csvEsc(r[h])).join(";"))].join("\r\n");return "\uFEFF"+body;}

function toast(msg,type="error"){
  let old=document.getElementById("legalToast");if(old)old.remove();
  let t=document.createElement("div");t.id="legalToast";
  t.style.cssText="position:fixed;top:30px;left:50%;transform:translateX(-50%) scale(.95);z-index:99999999;padding:14px 22px;border-radius:14px;font-family:Georgia,serif;font-size:14px;letter-spacing:.3px;backdrop-filter:blur(10px);background:"+(type==="error"?"linear-gradient(135deg,#2b1212,#140808)":"linear-gradient(135deg,#102016,#08110c)")+";border:1px solid "+(type==="error"?"rgba(255,90,90,.35)":"rgba(120,255,180,.35)")+";color:"+(type==="error"?"#ffb3b3":"#c8ffd8")+";box-shadow:0 20px 60px rgba(0,0,0,.6);opacity:0;transition:.35s cubic-bezier(.2,.8,.2,1);";
  t.innerText=msg;document.body.appendChild(t);
  requestAnimationFrame(()=>{t.style.opacity=1;t.style.transform="translateX(-50%) scale(1)";});
  setTimeout(()=>{t.style.opacity=0;t.style.transform="translateX(-50%) scale(.92)";setTimeout(()=>t.remove(),300);},3500);
}
function closePanel(){["pdfCreatePanel","pdfPanel","legalDateModal","legalFilterModal"].forEach(id=>{let e=document.getElementById(id);if(e)e.remove();});}
function etaText(){let done=UI.current||0;if(!done||!UI.startedAt)return "-";let sec=(Date.now()-UI.startedAt)/1000;let rate=done/sec;let left=Math.max(0,UI.total-done);let eta=rate>0?Math.round(left/rate):0;let m=Math.floor(eta/60),s=eta%60;return m+"dk "+s+"sn";}
function speedText(){let done=UI.current||0;if(!done||!UI.startedAt)return "-";let sec=(Date.now()-UI.startedAt)/1000;return (done/sec).toFixed(2)+" kayıt/sn";}
function injectStyle(){
  let old=document.getElementById("pdfCreatePanelStyle");
  if(old)old.remove();

  let s=document.createElement("style");
  s.id="pdfCreatePanelStyle";

  s.innerHTML=[
    "#pdfCreatePanel{position:fixed;right:24px;bottom:24px;z-index:999999;width:430px;color:#f8f3e8;font-family:Georgia,serif;background:radial-gradient(circle at top left,rgba(214,178,94,.22),transparent 35%),linear-gradient(145deg,#12100c,#1c1812 55%,#080806);border:1px solid rgba(214,178,94,.35);border-radius:22px;box-shadow:0 24px 70px rgba(0,0,0,.65),inset 0 1px 0 rgba(255,255,255,.08);overflow:hidden}",
    ".legal-head{position:relative;padding:18px 18px 12px;border-bottom:1px solid rgba(214,178,94,.18)}",
    ".legal-title{font-size:21px;color:#ffe3a3;font-weight:bold}",
    ".legal-sub{margin-top:5px;font-size:11px;color:#b8aa8a;text-transform:uppercase;letter-spacing:1.8px}",
    ".legal-body{position:relative;padding:16px 18px 18px}",
    ".legal-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin-bottom:14px}",
    ".legal-card{background:rgba(255,255,255,.055);border:1px solid rgba(255,255,255,.08);border-radius:14px;padding:9px}",
    ".legal-num{font-size:18px;font-weight:800;color:#fff7df}",
    ".legal-label{font-size:9px;color:#a99b80;margin-top:2px}",
    ".legal-progress{height:9px;background:rgba(255,255,255,.08);border-radius:99px;overflow:hidden;border:1px solid rgba(255,255,255,.08)}",
    ".legal-bar{height:100%;width:0%;background:linear-gradient(90deg,#b7832f,#ffe3a3,#c9923e);box-shadow:0 0 18px rgba(255,211,129,.5);transition:width .18s linear}",
    "#pdfCreateLog{margin-top:12px;font-size:13px;line-height:1.45;color:#d8ccb2;white-space:pre-line;min-height:64px}",
    ".legal-badge{display:inline-flex;align-items:center;gap:6px;margin-top:12px;margin-right:6px;padding:7px 10px;border-radius:999px;background:rgba(214,178,94,.12);color:#ffe3a3;font-size:12px;border:1px solid rgba(214,178,94,.25)}",
    ".pulse{width:7px;height:7px;background:#e6b85c;border-radius:50%}",
    ".danger-btn{margin-top:12px;width:100%;padding:10px;border-radius:14px;border:1px solid rgba(255,90,90,.3);background:rgba(255,90,90,.08);color:#ffb3b3;font-weight:bold;cursor:pointer}"
  ].join("");

  document.head.appendChild(s);
}
function panel(){closePanel();injectStyle();let p=document.createElement("div");p.id="pdfCreatePanel";p.innerHTML=`<div class="legal-head"><div class="legal-title">Made İn DMR</div><div class="legal-sub">${VERSION} · concurrency ${PRO.CONCURRENCY}</div></div><div class="legal-body"><div class="legal-grid"><div class="legal-card"><div class="legal-num" id="uiTotal">0</div><div class="legal-label">Toplam</div></div><div class="legal-card"><div class="legal-num" id="uiCurrent">0</div><div class="legal-label">İşlenen</div></div><div class="legal-card"><div class="legal-num" id="uiAdded">0</div><div class="legal-label">Eklenen</div></div><div class="legal-card"><div class="legal-num" id="uiFailed">0</div><div class="legal-label">Hata</div></div><div class="legal-card"><div class="legal-num" id="uiSkipped">0</div><div class="legal-label">Atlanan</div></div></div><div class="legal-progress"><div class="legal-bar" id="uiBar"></div></div><div id="pdfCreateLog">Hazır</div><div class="legal-badge"><span class="pulse"></span><span id="uiSpeed">-</span></div><div class="legal-badge">ETA: <span id="uiEta">-</span></div><button id="dmrCancelBtn" class="danger-btn">İşlemi Durdur</button></div>`;document.body.appendChild(p);document.getElementById("dmrCancelBtn").onclick=()=>{CANCEL=true;toast("Durdurma isteği alındı. Aktif işlem bitince duracak.","success");};}
function log(t){if(UI.last!==t){UI.last=t;let l=document.getElementById("pdfCreateLog");if(l)l.innerText=t;}let vals={uiTotal:UI.total,uiCurrent:UI.current,uiAdded:UI.added,uiFailed:UI.failed,uiSkipped:UI.skipped};for(let id in vals){let e=document.getElementById(id);if(e)e.innerText=vals[id];}let b=document.getElementById("uiBar");let pct=UI.total>0?Math.min(100,Math.round(UI.current/UI.total*100)):0;if(b)b.style.width=pct+"%";let sp=document.getElementById("uiSpeed");if(sp)sp.innerText=speedText();let eta=document.getElementById("uiEta");if(eta)eta.innerText=etaText();}
function modalShell(id){let m=document.createElement("div");m.id=id;m.style.cssText="position:fixed;inset:0;z-index:9999999;background:rgba(0,0,0,.55);backdrop-filter:blur(8px);display:flex;align-items:center;justify-content:center;font-family:Georgia,serif;";m.innerHTML=`<div id="${id}Box" style="width:460px;background:radial-gradient(circle at top left,rgba(214,178,94,.22),transparent 35%),linear-gradient(145deg,#12100c,#1c1812 55%,#080806);border:1px solid rgba(214,178,94,.35);color:#f8f3e8;border-radius:24px;box-shadow:0 28px 90px rgba(0,0,0,.7);overflow:hidden;"></div>`;document.body.appendChild(m);return m;}
function dateModal(){return new Promise(resolve=>{let old=document.getElementById("legalDateModal");if(old)old.remove();let m=modalShell("legalDateModal");let box=document.getElementById("legalDateModalBox");let st=loadState();box.innerHTML=`<div style="padding:22px 24px;border-bottom:1px solid rgba(214,178,94,.18);"><div style="font-size:25px;color:#ffe3a3;font-weight:bold;">DMR Mevzuat Archiver PRO</div><div style="margin-top:6px;font-size:12px;letter-spacing:1.6px;color:#b8aa8a;text-transform:uppercase;">Tarih aralığı ve format seçimi</div></div><div style="padding:22px 24px;">${st?`<div id="resumeNotice" style="margin-bottom:14px;padding:10px 12px;border-radius:12px;background:rgba(214,178,94,.1);border:1px solid rgba(214,178,94,.25);font-size:12px;color:#ffe3a3;">Önceki işlem kaydı bulundu. Aynı seçimlerle devam edersen kaldığı yerden başlar.</div>`:""}<label style="font-size:12px;color:#d8ccb2;">Karar Türü</label><select id="dKind" style="width:100%;box-sizing:border-box;margin-top:8px;margin-bottom:16px;padding:13px 14px;border-radius:14px;border:1px solid rgba(214,178,94,.3);background:#1c1812;color:#fff7df;font-size:15px;outline:none;"><option value="istinaf">İstinaf</option><option value="yuksek">Yüksek Mahkeme</option></select><label style="font-size:12px;color:#d8ccb2;">Başlangıç Tarihi</label><input id="dStart" type="date" value="${today()}" style="width:100%;box-sizing:border-box;margin-top:8px;margin-bottom:16px;padding:13px 14px;border-radius:14px;border:1px solid rgba(214,178,94,.3);background:rgba(255,255,255,.06);color:#fff7df;font-size:15px;outline:none;"><label style="font-size:12px;color:#d8ccb2;">Bitiş Tarihi</label><input id="dEnd" type="date" value="${today()}" style="width:100%;box-sizing:border-box;margin-top:8px;margin-bottom:16px;padding:13px 14px;border-radius:14px;border:1px solid rgba(214,178,94,.3);background:rgba(255,255,255,.06);color:#fff7df;font-size:15px;outline:none;"><label style="font-size:12px;color:#d8ccb2;">Format</label><select id="dFormat" style="width:100%;box-sizing:border-box;margin-top:8px;margin-bottom:20px;padding:13px 14px;border-radius:14px;border:1px solid rgba(214,178,94,.3);background:#1c1812;color:#fff7df;font-size:15px;outline:none;"><option value="PDF">PDF</option><option value="WORD">WORD</option><option value="UDF">UDF</option></select><div style="display:flex;gap:10px;"><button id="dCancel" style="flex:1;padding:12px;border-radius:14px;border:1px solid rgba(255,255,255,.12);background:rgba(255,255,255,.06);color:#d8ccb2;font-weight:bold;cursor:pointer;">Vazgeç</button><button id="dClear" style="flex:1;padding:12px;border-radius:14px;border:1px solid rgba(255,90,90,.22);background:rgba(255,90,90,.08);color:#ffb3b3;font-weight:bold;cursor:pointer;">Kaydı Temizle</button><button id="dRun" style="flex:1;padding:12px;border-radius:14px;border:0;background:linear-gradient(90deg,#b7832f,#ffe3a3,#c9923e);color:#1b1408;font-weight:bold;cursor:pointer;box-shadow:0 12px 30px rgba(214,178,94,.25);">Filtreleri Getir</button></div></div>`;document.getElementById("dCancel").onclick=()=>{m.remove();resolve(null);};document.getElementById("dClear").onclick=()=>{clearState();let r=document.getElementById("resumeNotice");if(r)r.remove();toast("Kayıt temizlendi.","success");};document.getElementById("dRun").onclick=()=>{let picked={kind:document.getElementById("dKind").value,start:document.getElementById("dStart").value,end:document.getElementById("dEnd").value,format:document.getElementById("dFormat").value};m.remove();resolve(picked);};});}
function filterModal(options,total){return new Promise(resolve=>{let old=document.getElementById("legalFilterModal");if(old)old.remove();let m=modalShell("legalFilterModal");let box=document.getElementById("legalFilterModalBox");let opts=options.map(x=>`<option value="${x.value}">${x.label}</option>`).join("");box.innerHTML=`<div style="padding:22px 24px;border-bottom:1px solid rgba(214,178,94,.18);"><div style="font-size:25px;color:#ffe3a3;font-weight:bold;">Daire Harf Filtresi</div><div style="margin-top:6px;font-size:12px;letter-spacing:1.6px;color:#b8aa8a;text-transform:uppercase;">${total} kayıt tarandı</div></div><div style="padding:22px 24px;"><label style="font-size:12px;color:#d8ccb2;">Harf Grubu</label><select id="dDynamicFilter" style="width:100%;box-sizing:border-box;margin-top:8px;margin-bottom:20px;padding:13px 14px;border-radius:14px;border:1px solid rgba(214,178,94,.3);background:#1c1812;color:#fff7df;font-size:15px;outline:none;">${opts}</select><div style="font-size:12px;color:#b8aa8a;margin-bottom:18px;line-height:1.5;">PRO mod: Aynı anda ${PRO.CONCURRENCY} kontrollü indirme yapılır.</div><div style="display:flex;gap:10px;"><button id="fCancel" style="flex:1;padding:12px;border-radius:14px;border:1px solid rgba(255,255,255,.12);background:rgba(255,255,255,.06);color:#d8ccb2;font-weight:bold;cursor:pointer;">Vazgeç</button><button id="fRun" style="flex:1;padding:12px;border-radius:14px;border:0;background:linear-gradient(90deg,#b7832f,#ffe3a3,#c9923e);color:#1b1408;font-weight:bold;cursor:pointer;box-shadow:0 12px 30px rgba(214,178,94,.25);">Arşivi Başlat</button></div></div>`;document.getElementById("fCancel").onclick=()=>{m.remove();resolve(null);};document.getElementById("fRun").onclick=()=>{let f=document.getElementById("dDynamicFilter").value;m.remove();resolve(f);};});}
async function loadScript(src){return new Promise((res,rej)=>{if([...document.scripts].some(s=>s.src===src))return res();let s=document.createElement("script");s.src=src;s.onload=res;s.onerror=()=>rej(new Error("LIB_LOAD_FAILED"));document.body.appendChild(s);});}

async function runQueue(tasks,worker,concurrency){
  let next=0;
  async function loop(){
    while(next<tasks.length&&!CANCEL){
      let i=next++;
      await worker(tasks[i],i);
      await sleep(PRO.REQUEST_DELAY_MS);
    }
  }
  await Promise.all(Array.from({length:Math.min(concurrency,tasks.length)},loop));
}

try{
  UI={total:0,current:0,added:0,failed:0,skipped:0,last:"",startedAt:0};CANCEL=false;
  let picked=await dateModal();if(!picked)return;
  let cfg=CONFIG[picked.kind];if(!cfg){toast("Karar türü seçilemedi.");return;}
  if(!validDate(picked.start)||!validDate(picked.end)){toast("Geçersiz tarih.");return;}
  if(parseDate(picked.start)>parseDate(picked.end)){toast("Başlangıç tarihi bitiş tarihinden büyük olamaz.");return;}
  panel();log("Liste ve filtre bilgileri hazırlanıyor...");
  let allLists=await fetchLists(cfg,range(picked.start,picked.end));
  let totalRecords=allLists.reduce((a,b)=>a+b.list.length,0);
  if(!totalRecords){closePanel();toast("Bu tarih aralığında kayıt bulunmadı.");return;}
  allLists=enrichAll(allLists);closePanel();
  let options=buildOptions(allLists);let selected=await filterModal(options,totalRecords);if(!selected)return;
  let key=runKey(picked,selected);let prev=loadState();let resume=prev&&prev.runKey===key?Number(prev.nextIndex||0):0;
  panel();
  if(!window.JSZip){log("ZIP motoru yükleniyor...");await loadScript(JSZIP_URL);}
  let zip=new JSZip(),used=new Set(),failedRows=[],skippedRows=[],flat=[];
  for(let b of allLists){for(let it of b.list){flat.push({date:b.date,item:it});}}
  UI.total=flat.length;UI.startedAt=Date.now();
  let lock=Promise.resolve();
  let added=0,failed=0,skipped=0,maxDone=resume;
  let tasks=flat.slice(resume).map((row,offset)=>({row,idx:resume+offset}));
  log("İndirme başlıyor\nTür: "+cfg.label+"\nFiltre: "+selected+"\nToplam: "+flat.length+(resume?("\nKaldığı yer: "+resume):""));

  await runQueue(tasks,async(task)=>{
    let idx=task.idx,row=task.row,d=row.date,it=row.item;
    if(CANCEL)return;
    UI.current=Math.max(UI.current,idx+1);
    saveState({runKey:key,picked,selectedFilter:selected,nextIndex:idx,stats:{added,failed,skipped}});
    if(!passFilter(it,selected)){
      skipped++;UI.skipped=skipped;
      skippedRows.push({"Tarih":d,"ListeID":it?.id||"","Daire":it.__daireText||apiDaireRaw(it),"Konu":it.__konu||apiKonu(it),"Sebep":selected+" filtresine uymadığı için atlandı"});
      maxDone=Math.max(maxDone,idx+1);saveState({runKey:key,picked,selectedFilter:selected,nextIndex:maxDone,stats:{added,failed,skipped}});
      log("Filtre dışı kayıt atlandı\nİşlenen: "+UI.current+"/"+flat.length+"\nEklenen: "+added+" Hata: "+failed+" Atlanan: "+skipped);
      return;
    }
    try{
      log(picked.format+" indiriliyor\nTür: "+cfg.label+"\nKayıt: "+(idx+1)+"/"+flat.length);
      let blob=await getFile(cfg,it,picked.format);
      if(!blob){failed++;UI.failed=failed;failedRows.push({"Tarih":d,"ListeID":it?.id||"","Daire":it.__daireText||apiDaireRaw(it),"Konu":it.__konu||apiKonu(it),"Sebep":"URL veya gerçek dosya alınamadı"});return;}
      let folder=folderName(it);let base=siteFileName(it);let name=uniqueName(used,folder,base,ext(picked.format));
      await (lock=lock.then(()=>{zip.folder(folder).file(name,blob);}));
      added++;UI.added=added;
      maxDone=Math.max(maxDone,idx+1);saveState({runKey:key,picked,selectedFilter:selected,nextIndex:maxDone,stats:{added,failed,skipped}});
      log(picked.format+" eklendi\nKlasör: "+folder+"\nDosya: "+name+"\nİşlenen: "+UI.current+"/"+flat.length+"\nEklenen: "+added+" Hata: "+failed+" Atlanan: "+skipped);
    }catch(e){
      if(e.message==="LIMIT"){saveState({runKey:key,picked,selectedFilter:selected,nextIndex:idx,stats:{added,failed,skipped},stoppedReason:"LIMIT"});throw e;}
      failed++;UI.failed=failed;failedRows.push({"Tarih":d,"ListeID":it?.id||"","Daire":it.__daireText||apiDaireRaw(it),"Konu":it.__konu||apiKonu(it),"Sebep":e.message});console.error(e,it);
    }
  },PRO.CONCURRENCY);

  if(CANCEL){toast("İşlem durduruldu. Aynı seçimlerle devam edebilirsin.");return;}
  await lock;
  if(failedRows.length)zip.file("indirilemeyen_kayitlar_raporu.csv",makeCsv(["Tarih","ListeID","Daire","Konu","Sebep"],failedRows));
  if(skippedRows.length)zip.file("filtre_nedeniyle_atlanan_kayitlar.csv",makeCsv(["Tarih","ListeID","Daire","Konu","Sebep"],skippedRows));
  if(!added){closePanel();toast("Hiç gerçek dosya indirilemedi. Console ID_CANDIDATES ve PRINT_REQUEST çıktılarını kontrol et.");console.warn("["+APP+"] İndirilemeyen kayıtlar:",failedRows);return;}
  log("ZIP hazırlanıyor\nTür: "+cfg.label+"\nFiltre: "+selected+"\nDosya: "+added+"\nHata: "+failed+"\nAtlanan: "+skipped);
  let out=await zip.generateAsync({type:"blob"});
  let a=document.createElement("a");a.href=URL.createObjectURL(out);a.download=cfg.prefix+"-"+safe(selected,40).toLowerCase()+"-"+picked.format.toLowerCase()+"-"+picked.start+"-"+picked.end+".zip";document.body.appendChild(a);a.click();
  setTimeout(()=>{URL.revokeObjectURL(a.href);a.remove();},1000);
  clearState();log("ZIP indirildi\nDosya: "+added+"\nHata: "+failed+"\nAtlanan: "+skipped);closePanel();toast("PRO işlem başarılı şekilde tamamlandı.","success");
}catch(e){
  closePanel();
  if(e.message==="LIMIT")toast("Günlük işlem kotasına ulaşıldı. Aynı seçimlerle tekrar başlatırsan kaldığı yerden devam eder.");
  else if(e.message==="LIB_LOAD_FAILED")toast("ZIP motoru yüklenemedi.");
  else{console.error(e);toast("Beklenmeyen hata oluştu. Console detayını kontrol et.");}
}

})();
